class Solution {
public:
    vector<int> lexicalOrder(int n) {
        vector<int> res;
        for (int i = 1; i <= n; i++) {
            if (i <= 9) res.push_back(i);
            else {
                int j = i;
                while (j > 9) j /= 10;
                while (j > 1) {
                    res.push_back(i);
                    j--;
                }
            }
        }
        return res;
    }
};
